// Workflow A5: Build DAILY_PLAN rows for "today"
// Inputs (from previous nodes):
// - A2: ZONES rows
// - A3: RULES rows (format B: rule_key, rule_value)
// - A4: Forecast_24hr_Current summary rows
// - A6: DAILY_PLAN existing rows (to detect if today already planned)

function zaTodayISO() {
  // YYYY-MM-DD in Africa/Johannesburg
  const fmt = new Intl.DateTimeFormat("en-CA", {
    timeZone: "Africa/Johannesburg",
    year: "numeric",
    month: "2-digit",
    day: "2-digit",
  });
  return fmt.format(new Date());
}

function toNum(v, fallback = 0) {
  const n = Number(v);
  return Number.isFinite(n) ? n : fallback;
}

function clamp(n, min, max) {
  return Math.max(min, Math.min(max, n));
}

// --- pull data from other nodes ---
const zones = $items("A2 - Get ZONES")
  .map(i => i.json)
  .filter(z => (z.zone_id ?? "").toString().trim() !== "");

const rulesRows = $items("A3 - Get RULES").map(i => i.json);
const forecastRows = $items("A4 - Get Forecast_24h Summary").map(i => i.json);
const existingPlanRows = $items("A6 - Check Existing Plan (Today)").map(i => i.json);

// --- normalize RULES (format B) into object ---
const rules = {};
for (const r of rulesRows) {
  const k = (r.rule_key ?? r.wind_pause_kmh ?? r[Object.keys(r)[0]] ?? "").toString().trim();
  const v = r.rule_value ?? r[Object.keys(r)[1]];
  if (k) rules[k] = v;
}

// --- pick forecast summary row (first row returned) ---
const fc = forecastRows[0] ?? {};
const forecast_updated_at = fc.forecast_updated_at ?? fc.forecast_updated ?? fc.run_timestamp ?? "";
const rain24 = toNum(fc.rain_total_next_24h_mm ?? fc.rain_total_next_24h ?? fc.rain_sum_mm, 0);
const windMax24 = toNum(fc.max_wind_next_24h_kmh ?? fc.wind_max_kmh, 0);
const gustMax24 = toNum(fc.max_gust_next_24h_kmh ?? fc.gust_max_kmh, 0);
const tMin24 = toNum(fc.temp_min_next_24h_c ?? fc.temp_min_c, 0);
const tMax24 = toNum(fc.temp_max_next_24h_c ?? fc.temp_max_c, 0);

// --- today + check if already planned ---
const today = zaTodayISO();
const alreadyPlanned = existingPlanRows.some(r => (r.date ?? "").toString().slice(0, 10) === today);

// --- thresholds ---
const rain_skip_threshold = toNum(rules["rain_forecast_skip_mm_24h"], 9999);
const min_runtime = toNum(rules["min_runtime_minutes"], 5);
const max_runtime = toNum(rules["max_runtime_minutes"], 120);

// --- simple season choice (v1): hot day = summer minutes ---
const useSummer = tMax24 >= 25;

// --- build plan rows ---
let planRows = [];
let skipAll = rain24 >= rain_skip_threshold;

const sortedZones = [...zones].sort((a, b) => {
  const pa = toNum(a.priority, 99);
  const pb = toNum(b.priority, 99);
  if (pa !== pb) return pa - pb;
  return (a.zone_id ?? "").toString().localeCompare((b.zone_id ?? "").toString());
});

for (const z of sortedZones) {
  const zoneId = (z.zone_id ?? "").toString().trim();
  const plan_id = `${today}_${zoneId}`;

  const base = useSummer ? toNum(z.summer_minutes, 0) : toNum(z.winter_minutes, 0);
  const planned_minutes = clamp(base, min_runtime, max_runtime);

  const status = skipAll ? "SKIPPED" : "PLANNED";
  const reason = skipAll
    ? `Skipped: rain forecast next 24h (${rain24}mm) >= threshold (${rain_skip_threshold}mm)`
    : "";

  planRows.push({
    plan_id,
    date: today,
    zone_id: zoneId,
    planned_start: "",                 // controller (Workflow B) will choose runtime window
    planned_minutes: String(planned_minutes),
    status,
    reason,
    actual_start: "",
    actual_end: "",
    water_score: String(toNum(z.priority, 99)), // simple score for now
  });
}

// next zone = first PLANNED
const next = planRows.find(r => r.status === "PLANNED")?.zone_id ?? "";

// totals for log
const totalPlannedMinutes = planRows
  .filter(r => r.status === "PLANNED")
  .reduce((sum, r) => sum + toNum(r.planned_minutes, 0), 0);

const weather_snapshot =
  `rain24=${rain24}mm, windMax=${windMax24}km/h, gustMax=${gustMax24}km/h, tMin=${tMin24}°C, tMax=${tMax24}°C, updated=${forecast_updated_at}`;

// IMPORTANT: Return ONE item only (prevents repeated reads/appends)
return [
  {
    json: {
      today,
      alreadyPlanned,
      planRows,
      next_zone_id: next,
      totalPlannedMinutes,
      weather_snapshot,
      forecast_updated_at
    }
  }
];

